func TestNovelContributionsTotalsAggregatesItems(t *testing.T) {
	cases := []struct {
		name       string
		year       string
		wantAmount float64
		wantItems  float64
	}{
		{name: "sums matching LD-203 items", year: "2024", wantAmount: 150, wantItems: 2},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			dbPath := newLDANovelTestDB(t)
			seedLDANovelRecord(t, dbPath, "contributions", "c1", `{"id":1,"filing_uuid":"c1","filing_year":2024,"filing_period":"mid_year","filing_period_display":"Mid-Year","contribution_items":[{"contribution_type":"feca","contribution_type_display":"FECA","contributor_name":"Jane Doe","payee_name":"PAC A","honoree_name":"Candidate A","amount":"100.00"},{"contribution_type":"feca","contribution_type_display":"FECA","contributor_name":"Jane Doe","payee_name":"PAC A","honoree_name":"Candidate A","amount":"50.00"}]}`)
			seedLDANovelRecord(t, dbPath, "contributions", "c2", `{"id":2,"filing_uuid":"c2","filing_year":2023,"filing_period":"year_end","contribution_items":[{"contribution_type":"feca","contributor_name":"Jane Doe","payee_name":"PAC A","amount":"999.00"}]}`)
			flags := &rootFlags{asJSON: true}
			rows := runLDANovelRows(t, newNovelContributionsTotalsCmd(flags), "--db", dbPath, "--year", tc.year)
			if len(rows) != 1 {
				t.Fatalf("rows = %#v, want one aggregate", rows)
			}
			if rows[0]["amount"].(float64) != tc.wantAmount || rows[0]["items"].(float64) != tc.wantItems {
				t.Fatalf("row = %#v, want amount %v items %v", rows[0], tc.wantAmount, tc.wantItems)
			}
		})
	}
}

func TestNovelContributionsTotalsHintsWhenContributionsUnsynced(t *testing.T) {
	dbPath := newLDANovelTestDB(t)
	seedLDANovelRecord(t, dbPath, "filings", "f1", `{"id":1,"filing_uuid":"f1","filing_year":2024,"filing_period":"mid_year"}`)
	seedLDANovelSyncState(t, dbPath, "filings")

	flags := &rootFlags{asJSON: true}
	rows, stderr := runLDANovelRowsWithStderr(t, newNovelContributionsTotalsCmd(flags), "--db", dbPath, "--year", "2024")
	if len(rows) != 0 {
		t.Fatalf("rows = %#v, want no contribution totals", rows)
	}
	if !strings.Contains(stderr, "sync --resources contributions") {
		t.Fatalf("stderr = %q, want targeted contributions sync hint", stderr)
	}
}
